export const SkeletonAvatar = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex w-fit items-center gap-4')],
    [
      skeleton('size-10 shrink-0 rounded-full'),
      h.div(
        [h.Class('grid gap-2')],
        [skeleton('h-4 w-[150px]'), skeleton('h-4 w-[100px]')],
      ),
    ],
  )
}

export const SkeletonDemo = (): Html => {
